const html = $json.data || $json.body || '';

// Basis-URL für relative Link-Auflösung
const PAGE_BASE = 'https://www.goslar.de/stadt/politik/allris/vo040_r.asp';

const matches = [...html.matchAll(/href=["']([^"']*vo020_r\.asp\?VOLFDNR=\d+)[^"']*["']/gi)];

// Deduplizierung primär nach volfdnr (Haupt-Schlüssel),
// Fallback für Links ohne volfdnr nach URL.
const seenVolfdnr     = new Set();
const seenFallbackUrls = new Set();

const links = [];

for (const m of matches) {
  const rawHref = m[1].replace(/&amp;/g, '&');

  let resolvedUrl;
  try {
    resolvedUrl = rawHref.startsWith('http')
      ? rawHref
      : new URL(rawHref, PAGE_BASE).href;
  } catch(e) {
    resolvedUrl = rawHref;
  }

  const volfdnr = String(resolvedUrl || '').match(/VOLFDNR=(\d+)/i)?.[1] || '';

  if (volfdnr) {
    if (seenVolfdnr.has(volfdnr)) {
      console.warn(`[Extrahiere Vorgangslinks] Doppelte VOLFDNR übersprungen: ${volfdnr}`);
      continue;
    }
    seenVolfdnr.add(volfdnr);
  } else {
    if (seenFallbackUrls.has(resolvedUrl)) {
      continue;
    }
    seenFallbackUrls.add(resolvedUrl);
  }

  // Kanonische URL: immer sauber ohne Zusatzparameter
  const canonicalUrl = volfdnr
    ? `https://www.goslar.de/stadt/politik/allris/vo020_r.asp?VOLFDNR=${volfdnr}`
    : resolvedUrl;

  links.push({
    json: {
      source:    'ALLRIS Goslar',
      url:        canonicalUrl,
      sourceUrl:  canonicalUrl,
      allrisUrl:  canonicalUrl,
      docId:      volfdnr,
      volfdnr,
      type:       'vorgang'
    }
  });
}

const total = links.length;

links.forEach(item => {
  item.json.debug_totalVorgangslinks = total;
  item.json.debug_currentVolfdnr     = item.json.volfdnr || '';
  item.json.debug_sourceUrlPresent   = !!item.json.sourceUrl;
  item.json.debug_allrisUrlPresent   = !!item.json.allrisUrl;
  item.json.debug_loopPhase          = 'vorgangslinks_extracted';
});

console.log(`[Extrahiere Vorgangslinks] Gefunden: ${total} eindeutige Links`);

return links;

const out = [];

const ALLOWED_FILE_EXTENSIONS = [
  'pdf',
  'jpg',
  'jpeg',
  'png',
  'gif',
  'tif',
  'tiff',
  'doc',
  'docx',
  'xls',
  'xlsx',
  'ppt',
  'pptx',
  'odt',
  'ods',
  'zip'
];

function cleanText(html) {
  return String(html || '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function resolveUrl(rawHref, baseUrl) {
  const href = String(rawHref || '').replace(/&amp;/g, '&').trim();

  try {
    return href.startsWith('http')
      ? href
      : new URL(href, baseUrl).href;
  } catch (e) {
    if (href.startsWith('/')) {
      return 'https://www.goslar.de' + href;
    }
    return 'https://www.goslar.de/stadt/politik/allris/' + href;
  }
}

function getExtensionFromUrl(url) {
  const clean = String(url || '').split('?')[0].split('#')[0];
  const m = clean.match(/\.([a-zA-Z0-9]{2,6})$/);
  return m ? m[1].toLowerCase() : '';
}

function isRealDocumentCandidate(url) {
  const u = String(url || '').toLowerCase();
  const ext = getExtensionFromUrl(u);

  if (!u) return false;

  // ALLRIS-Dokument-Download
  if (u.includes('/stadt/politik/allris/do027.asp')) return true;
  if (u.includes('dolfdnr=')) return true;

  // Temporäre ALLRIS-Dateipfade
  // Wichtig: auch wenn ALLRIS nicht sauber "PDF" ausweist.
  if (u.includes('/stadt/politik/allris/___tmp/tmp/')) return true;
  if (u.includes('/allris/___tmp/tmp/')) return true;

  // Direkte Datei-Links
  if (ext && ALLOWED_FILE_EXTENSIONS.includes(ext)) return true;

  return false;
}

function classifyDocument(url, label, surroundingHtml) {
  const u = String(url || '').toLowerCase();
  const l = String(label || '').toLowerCase();
  const ctx = cleanText(surroundingHtml || '').toLowerCase();

  const isAnlage =
    ctx.includes('anlagen') ||
    ctx.includes('anlage') ||
    l.includes('anlage') ||
    l.includes('anlagen') ||
    u.includes('/anlagen/') ||
    u.includes('-anlagen/');

  const isVorlage =
    ctx.includes('dokumente') ||
    ctx.includes('vorlage') ||
    l.includes('vorlage') ||
    u.includes('vorlage');

  if (isAnlage) return 'anlage';
  if (isVorlage) return 'original';
  return 'document';
}

function buildDocKey(url, type, label) {
  const u = String(url || '');
  const dol = u.match(/DOLFDNR=(\d+)/i)?.[1];

  if (dol) return `dol_${dol}`;

  let fileName = '';
  try {
    const parsed = new URL(u);
    fileName = decodeURIComponent(parsed.pathname.split('/').pop() || '');
  } catch (e) {
    fileName = u.split('/').pop() || '';
  }

  fileName = fileName
    .split('?')[0]
    .split('#')[0]
    .replace(/[^a-zA-Z0-9._-]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, 120);

  if (fileName) {
    return `${type}_${fileName}`;
  }

  const fallback = cleanText(label || '')
    .replace(/[^a-zA-Z0-9._-]/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_+|_+$/g, '')
    .substring(0, 80);

  return fallback ? `${type}_${fallback}` : `${type}_unknown`;
}

for (const item of items) {
  const html = item.json.html || item.json.data || '';

  const baseUrl =
    item.json.allrisUrl ||
    item.json.sourceUrl ||
    'https://www.goslar.de/stadt/politik/allris/vo040_r.asp';

  const matches = [...html.matchAll(/<a\b[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi)];

  const found = [];
  const skipped = [];
  const seen = new Set();

  for (const match of matches) {
    const rawHref = match[1] || '';
    const rawLabel = match[2] || '';
    const label = cleanText(rawLabel);

    if (!rawHref) continue;

    const hrefLower = rawHref.toLowerCase();

    if (
      hrefLower.startsWith('#') ||
      hrefLower.startsWith('javascript:') ||
      hrefLower.startsWith('mailto:') ||
      hrefLower.startsWith('tel:')
    ) {
      continue;
    }

    const link = resolveUrl(rawHref, baseUrl);
    const urlLower = link.toLowerCase();

    // Vorgangs-/Übersichtsseiten nie als Dokument aufnehmen
    if (urlLower.includes('vo020_r.asp?volfdnr=')) continue;
    if (urlLower.includes('vo040_r.asp')) continue;

    const start = Math.max(0, match.index - 500);
    const end = Math.min(html.length, match.index + match[0].length + 500);
    const surroundingHtml = html.slice(start, end);

    // Entscheidender Punkt:
    // Der Kontext "Anlagen" darf NICHT reichen.
    // Nur der Link selbst muss wie Datei/ALLRIS-Download aussehen.
    if (!isRealDocumentCandidate(link)) {
      skipped.push(link);
      continue;
    }

    if (seen.has(link)) continue;
    seen.add(link);

    const type = classifyDocument(link, label, surroundingHtml);
    const docKey = buildDocKey(link, type, label);

    found.push({
      url: link,
      type,
      label,
      docKey
    });
  }

  console.log(
    `[Extrahiere Dokumentlinks] volfdnr=${item.json.volfdnr || '?'}: ` +
    `${found.length} echte Dokumentlinks, ${skipped.length} normale/irrelevante Links übersprungen.`
  );

  if (found.length > 0) {
    console.log(found.map(d => `${d.type}: ${d.url}`).join('\n'));
  }

  if (found.length === 0) {
    out.push({
      json: {
        title: item.json.title || '',
        sourceUrl: item.json.sourceUrl || item.json.allrisUrl || '',
        allrisUrl: item.json.allrisUrl || item.json.sourceUrl || '',
        volfdnr: item.json.volfdnr || '',
        documentUrl: '',
        type: 'none',
        label: '',
        docKey: '',
        debug_documentLinkCount: 0,
        debug_skippedLinkCount: skipped.length
      }
    });
    continue;
  }

  for (const doc of found) {
    out.push({
      json: {
        title: item.json.title || '',
        sourceUrl: item.json.sourceUrl || item.json.allrisUrl || '',
        allrisUrl: item.json.allrisUrl || item.json.sourceUrl || '',
        volfdnr: item.json.volfdnr || '',
        documentUrl: doc.url,
        type: doc.type,
        label: doc.label || '',
        docKey: doc.docKey || '',
        debug_documentLinkCount: found.length,
        debug_skippedLinkCount: skipped.length
      }
    });
  }
}

return out;

const out = [];
const seen = new Set();

for (const item of items) {
  const url       = item.json.documentUrl || '';
  const vorgangId = item.json.volfdnr || item.json.allrisUrl || item.json.title || 'unknown';

  const dedupKey = url
    ? `${vorgangId}::${url}`
    : `no_doc_${vorgangId}`;

  if (seen.has(dedupKey)) continue;
  seen.add(dedupKey);

  out.push({
    json: {
      title:         item.json.title        || '',
      sourceUrl:     item.json.sourceUrl    || '',
      allrisUrl:     item.json.allrisUrl    || item.json.sourceUrl || '',
      volfdnr:       item.json.volfdnr      || '',
      documentUrl:   url,
      type:          item.json.type         || (url
        ? (url.toLowerCase().endsWith('.pdf') ? 'pdf' : 'html')
        : 'none'),
      label:         item.json.label        || '',
      docKey:        item.json.docKey       || ''
    }
  });
}

return out;

const themen = {
  prioritaeten:             ['haushalt','finanzen','kosten','mittelbereitstellung','haushaltssatzung','spenden','eigenbetrieb','stadtwerke','sanierung','investition','förderung','zuschuss'],
  altstadt_unesco_wohnen:   ['altstadt','unesco','denkmalschutz','denkmal','wohnen','wohnraum','bebauungsplan','stadtentwicklung','gestaltungsfibel','sanierungsgebiet'],
  gesundheit_hausaerzte:    ['arzt','ärzte','hausarzt','gesundheit','medizin','krankenhaus','versorgung','defibrillator'],
  tierschutz:               ['tierschutz','tierheim','hund','katze','wildtier','tiere'],
  energie:                  ['energie','strom','wärme','windenergie','solar','photovoltaik','klima','schwammstadt'],
  inklusion_barrierefreiheit:['barrierefrei','barrierefreiheit','inklusion','behindert','rollstuhl','teilhabe','haltestelle'],
  transparenz_buerger:      ['anfrage','beantwortung','bürger','transparenz','verwaltung','software','app','digitalisierung'],
  verkehr:                  ['verkehr','straße','radweg','parkplatz','brücke','haltestelle','bus','parkflächen'],
  schulen_kitas:            ['schule','grundschule','kita','kindergarten','kindertagesstätte','sporthalle']
};
return items.map(item => {
  const text = ((item.json.title || '') + ' ' + (item.json.documentUrl || '')).toLowerCase();
  const treffer = [];
  for (const [thema, keywords] of Object.entries(themen)) {
    const hits = keywords.filter(k => text.includes(k));
    if (hits.length > 0) treffer.push({ thema, keywords: hits });
  }
  return { json: { ...item.json, vorfilterRelevant: treffer.length > 0,
    vorfilterThemen: treffer.map(t => t.thema), vorfilterKeywords: treffer.flatMap(t => t.keywords),
    vorfilterScore: Math.min(100, treffer.length * 20) } };
});

return items.map(item => {
  const url = item.json.documentUrl || '';

  const dol = url.match(/DOLFDNR=(\d+)/i)?.[1];

  let file = '';
  try {
    const u = new URL(url);
    file = decodeURIComponent(u.pathname.split('/').pop() || '');
  } catch (e) {
    file = url.split('/').pop() || '';
  }

  file = file
    .split('?')[0]
    .replace(/[^a-zA-Z0-9._-]/g, '_')
    .substring(0, 120);

  const type = item.json.type || 'document_candidate';

  let docKey;
  if (dol) {
    docKey = `dol_${dol}`;
  } else if (file) {
    docKey = `${type}_${file}`;
  } else {
    docKey = `${type}_${Buffer.from(url).toString('base64').substring(0, 24)}`;
  }

  return {
    json: {
      ...item.json,
      docKey,
      firstseen: new Date().toISOString(),
      lastseen: new Date().toISOString()
    }
  };
});

function extractVorgangsnummer(text) {
  if (!text) return '';
  const m = String(text).match(/\b(\d{4})\s*\/\s*(\d+)(?:-(\d+))?\b/);
  if (!m) return '';
  return m[1] + '/' + m[2] + (m[3] ? '-' + m[3] : '');
}

const HTTP_ERROR_TITLE_RE = /^\s*(?:400[\s:-]+bad\s+request|401[\s:-]+unauthorized|403[\s:-]+forbidden|404[\s:-]+not\s+found|408[\s:-]+request\s+time[- ]?out|429[\s:-]+too\s+many\s+requests|500[\s:-]+internal\s+server\s+error|501[\s:-]+not\s+implemented|502[\s:-]+bad\s+gateway|503[\s:-]+service\s+unavailable|504[\s:-]+gateway\s*time[- ]?out)\s*$/i;

const TECH_ERROR_PHRASE_RE = /gateway\s*time[- ]?out|bad\s+gateway|service\s+unavailable|internal\s+server\s+error|request\s+time[- ]?out|upstream\s+timed\s+out|proxy\s+error|temporarily\s+unavailable|too\s+many\s+requests|serverfehler|nginx\s+error|cloudflare\s+error/i;

function isTechnicalTitle(value) {
  const text = String(value || '').trim();
  return HTTP_ERROR_TITLE_RE.test(text) || TECH_ERROR_PHRASE_RE.test(text);
}

function containsTechnicalErrorPhrase(value) {
  return TECH_ERROR_PHRASE_RE.test(String(value || ''));
}

function isValidVorgangsnummer(v) {
  return /^\d{4}\/\d+(?:-\d+)?$/.test(String(v || '').trim());
}

// Gruppierung nach Vorgang – V29.1
const groups = {};

function parseVorgangsbeziehung(vorgangsnummer) {
  const value = String(vorgangsnummer || '').trim();
  const match = value.match(/^(\d{4})\s*\/\s*(\d+)(?:-(\d+))?$/);
  if (!match) {
    return { stammVorgangsnummer: value, folgeNummer: '', istFolgevorgang: false };
  }
  const jahr   = match[1];
  const nummer = match[2];
  const suffix = match[3] || '';
  return {
    stammVorgangsnummer: `${jahr}/${nummer}`,
    folgeNummer:         suffix,
    istFolgevorgang:     suffix !== ''
  };
}

for (const item of items) {
  const title = item.json.title || '';

  const volfdnr =
    item.json.volfdnr ||
    (item.json.sourceUrl || '').match(/VOLFDNR=(\d+)/i)?.[1] ||
    (item.json.allrisUrl || '').match(/VOLFDNR=(\d+)/i)?.[1] ||
    '';

  // Vorgangsnummer: bevorzugt aus item.json, dann aus title/html
  const vorgangsnummer =
    extractVorgangsnummer(item.json.vorgangsnummer || '') ||
    extractVorgangsnummer(title) ||
    extractVorgangsnummer(item.json.html || '');

  // vorgangKey immer vol_<VOLFDNR>
  const rawKey     = volfdnr ? `vol_${volfdnr}` : (vorgangsnummer || title);
  const vorgangKey = rawKey.replace(/[\/\-\s]/g, '_');

  const sourceUrl = volfdnr
    ? `https://www.goslar.de/stadt/politik/allris/vo020_r.asp?VOLFDNR=${volfdnr}`
    : (item.json.sourceUrl || item.json.allrisUrl || '');

  if (!groups[vorgangKey]) {
    groups[vorgangKey] = {
      vorgangKey,
      title,
      vorgangsnummer,
      volfdnr,
      sourceUrl,
      allrisUrl: sourceUrl,
      vorfilterThemen:   [],
      vorfilterKeywords: [],
      vorfilterScore:    0,
      documents:         [],
      ...parseVorgangsbeziehung(vorgangsnummer)
    };
  }

  for (const t of (item.json.vorfilterThemen || [])) {
    if (!groups[vorgangKey].vorfilterThemen.includes(t))
      groups[vorgangKey].vorfilterThemen.push(t);
  }
  for (const k of (item.json.vorfilterKeywords || [])) {
    if (!groups[vorgangKey].vorfilterKeywords.includes(k))
      groups[vorgangKey].vorfilterKeywords.push(k);
  }
  if ((item.json.vorfilterScore || 0) > groups[vorgangKey].vorfilterScore) {
    groups[vorgangKey].vorfilterScore = item.json.vorfilterScore;
  }
  if (item.json.documentUrl) {
    groups[vorgangKey].documents.push({
      url:    item.json.documentUrl,
      type:   item.json.type  || 'document_candidate',
      label:  item.json.label || '',
      docKey: item.json.docKey || ''
    });
  }
}

return Object.values(groups).map(v => ({
  json: {
    vorgangKey:          v.vorgangKey,
    volfdnr:             v.volfdnr           || '',
    title:               v.title,
    vorgangsnummer:      v.vorgangsnummer,
    sourceUrl:           v.sourceUrl         || '',
    allrisUrl:           v.allrisUrl         || v.sourceUrl || '',
    vorfilterThemen:     v.vorfilterThemen,
    vorfilterKeywords:   v.vorfilterKeywords,
    vorfilterScore:      v.vorfilterScore,
    documentsJson:       JSON.stringify(v.documents),
    documentCount:       v.documents.length,
    stammVorgangsnummer: v.stammVorgangsnummer || v.vorgangsnummer || '',
    folgeNummer:         v.folgeNummer        || '',
    istFolgevorgang:     v.istFolgevorgang    === true,
    debug_loopPhase:     'gruppierung_done',
    debug_currentVolfdnr: v.volfdnr || ''
  }
}));

function extractVorgangsnummer(text) {
  if (!text) return '';
  const m = String(text).match(/\b(\d{4})\s*\/\s*(\d+)(?:-(\d+))?\b/);
  if (!m) return '';
  return m[1] + '/' + m[2] + (m[3] ? '-' + m[3] : '');
}

const HTTP_ERROR_TITLE_RE = /^\s*(?:400[\s:-]+bad\s+request|401[\s:-]+unauthorized|403[\s:-]+forbidden|404[\s:-]+not\s+found|408[\s:-]+request\s+time[- ]?out|429[\s:-]+too\s+many\s+requests|500[\s:-]+internal\s+server\s+error|501[\s:-]+not\s+implemented|502[\s:-]+bad\s+gateway|503[\s:-]+service\s+unavailable|504[\s:-]+gateway\s*time[- ]?out)\s*$/i;

const TECH_ERROR_PHRASE_RE = /gateway\s*time[- ]?out|bad\s+gateway|service\s+unavailable|internal\s+server\s+error|request\s+time[- ]?out|upstream\s+timed\s+out|proxy\s+error|temporarily\s+unavailable|too\s+many\s+requests|serverfehler|nginx\s+error|cloudflare\s+error/i;

function isTechnicalTitle(value) {
  const text = String(value || '').trim();
  return HTTP_ERROR_TITLE_RE.test(text) || TECH_ERROR_PHRASE_RE.test(text);
}

function containsTechnicalErrorPhrase(value) {
  return TECH_ERROR_PHRASE_RE.test(String(value || ''));
}

function isValidVorgangsnummer(v) {
  return /^\d{4}\/\d+(?:-\d+)?$/.test(String(v || '').trim());
}

// Check if known – V29.1 mit erweitertem Metadatenvergleich
// $runIndex-sicher

function normalizeTitle(value) {
  return String(value || '').replace(/\s+/g, ' ').trim();
}

function normalizeVorgangsnummer(value) {
  const match = String(value || '').match(/\b(\d{4})\s*\/\s*(\d+)(?:-(\d+))?\b/);
  return match ? `${match[1]}/${match[2]}${match[3] ? '-' + match[3] : ''}` : '';
}

const databaseItems = $input.all(0, $runIndex);
const groupedItems  = $('Gruppierung nach Vorgang').all(0, $runIndex);

if (!groupedItems || groupedItems.length !== 1) {
  throw new Error(
    `[Check if known] Erwartet genau 1 aktuellen Vorgang, ` +
    `erhalten: ${groupedItems?.length ?? 0}, runIndex=${$runIndex}`
  );
}

const current = groupedItems[0].json || {};
const key     = String(current.vorgangKey || '').trim();

if (!key) {
  throw new Error('[Check if known] Aktueller Vorgang besitzt keinen vorgangKey.');
}

function normalizeDocsJson(raw) {
  try {
    let documents;
    if (Array.isArray(raw)) {
      documents = raw;
    } else {
      documents = JSON.parse(String(raw || '[]'));
    }
    if (!Array.isArray(documents)) return '[]';
    const urls = documents
      .map(d => (typeof d === 'string' ? d.trim() : String(d?.docKey || d?.url || '').trim()))
      .filter(Boolean)
      .sort();
    return JSON.stringify(urls);
  } catch (e) {
    console.warn(`[Check if known] documentsJson Lesefehler: ${e.message}`);
    return '[]';
  }
}

// Datenbankzeilen filtern
const matchingRows = databaseItems
  .map(item => item.json || {})
  .filter(row => String(row.vorgangKey || '').trim() === key);

const duplicateCount = matchingRows.length;
const isKnown        = duplicateCount > 0;

if (duplicateCount > 1) {
  console.warn(`[Check if known] Duplikate: key=${key}, count=${duplicateCount}, runIndex=${$runIndex}`);
}

let needsRefresh         = !isKnown;
let documentsChanged     = false;
let oldDocumentsJson     = '[]';
let oldDocumentCount     = 0;
let oldContentStage      = '';
let oldContentErrorReason = '';
let oldTitle             = '';
let oldVorgangsnummer    = '';
let oldMetadataInvalid   = false;
let metadataRepairNeeded = false;
let titleChanged         = false;
let vorgangsnummerChanged = false;
let normalizedOldTitle   = '';
let normalizedCurrentTitle = '';
let normalizedOldNumber  = '';
let normalizedCurrentNumber = '';

if (isKnown) {
  const old = matchingRows[0];

  oldDocumentsJson  = old.documentsJson  || '[]';
  oldDocumentCount  = Number.parseInt(String(old.documentCount || '0'), 10) || 0;
  oldContentStage       = String(old.contentStage || '').trim();
  oldContentErrorReason = String(old.contentErrorReason || '').trim();
  oldTitle          = String(old.title   || '').trim();
  oldVorgangsnummer = String(old.vorgangsnummer || '').trim();

  // Dokumentänderungen prüfen
  const newNorm = normalizeDocsJson(current.documentsJson);
  const oldNorm = normalizeDocsJson(oldDocumentsJson);
  documentsChanged = newNorm !== oldNorm;
  needsRefresh  = documentsChanged;

  // ContentStage-Fehler → immer refresh
  const oldIsContentError = oldContentStage === 'error' && (oldContentErrorReason === 'detail_failed' || oldContentErrorReason === 'metadata_error');
  if (oldIsContentError) {
    needsRefresh = true;
  }

  // Normalisierte Vergleiche
  normalizedOldTitle      = normalizeTitle(oldTitle);
  normalizedCurrentTitle  = normalizeTitle(current.title || '');
  normalizedOldNumber     = normalizeVorgangsnummer(oldVorgangsnummer);
  normalizedCurrentNumber = normalizeVorgangsnummer(current.vorgangsnummer || '');

  titleChanged =
    !!normalizedCurrentTitle &&
    normalizedOldTitle !== normalizedCurrentTitle;

  vorgangsnummerChanged =
    !!normalizedCurrentNumber &&
    normalizedOldNumber !== normalizedCurrentNumber;

  // Beschädigte Metadaten erkennen
  const titleEmpty       = !oldTitle;
  const titleTech        = isTechnicalTitle(oldTitle);
  const titlePlaceholder = oldTitle === '(Vorgangsseite nicht geladen)';
  const titleBad         = titleEmpty || titleTech || titlePlaceholder;

  const numMissing  = !oldVorgangsnummer;
  const numInvalid  = !isValidVorgangsnummer(oldVorgangsnummer);
  const urlMissing  = !old.allrisUrl && !old.sourceUrl;

  oldMetadataInvalid = titleBad || numMissing || numInvalid || urlMissing;

  // Reparatur auslösen wenn aktuelle Daten gültig und Bestand fehlerhaft/abweichend
  const currentHasValidTitle = !!(current.title) && !isTechnicalTitle(current.title);
  const currentHasValidNum   = isValidVorgangsnummer(current.vorgangsnummer);

  if (currentHasValidTitle && currentHasValidNum) {
    if (oldMetadataInvalid || titleChanged || vorgangsnummerChanged || oldIsContentError) {
      metadataRepairNeeded = true;
      needsRefresh         = true;
      console.log(
        `[Check if known] Metadaten-Reparatur: key=${key} ` +
        `oldTitle="${oldTitle}" → currentTitle="${current.title}" ` +
        `oldNum="${oldVorgangsnummer}" → currentNum="${current.vorgangsnummer}" ` +
        `oldMetadataInvalid=${oldMetadataInvalid} titleChanged=${titleChanged} ` +
        `vorgangsnummerChanged=${vorgangsnummerChanged}`
      );
    }
  }
}

console.log(
  `[Check if known] key=${key} isKnown=${isKnown} needsRefresh=${needsRefresh} ` +
  `oldContentStage=${oldContentStage} oldContentErrorReason=${oldContentErrorReason} oldMetadataInvalid=${oldMetadataInvalid} ` +
  `metadataRepairNeeded=${metadataRepairNeeded} titleChanged=${titleChanged} ` +
  `vorgangsnummerChanged=${vorgangsnummerChanged} duplicateCount=${duplicateCount} runIndex=${$runIndex}`
);

return [{
  json: {
    ...current,
    isKnown,
    needsRefresh,
    documentsChanged,
    oldDocumentsJson,
    oldDocumentCount,
    oldContentStage,
    oldContentErrorReason,
    oldTitle,
    oldVorgangsnummer,
    oldMetadataInvalid,
    metadataRepairNeeded,
    titleChanged,
    vorgangsnummerChanged,
    normalizedOldTitle,
    normalizedCurrentTitle,
    normalizedOldNumber,
    normalizedCurrentNumber,
    existingDuplicateCount: duplicateCount,
    debug_runIndex:  $runIndex,
    debug_loopPhase: isKnown
      ? (needsRefresh ? 'known_refresh' : 'known_unchanged')
      : 'new_vorgang'
  }
}];

const out = [];
for (const item of items) {
  let docs = [];
  try {
    docs = JSON.parse(item.json.documentsJson || '[]');
    if (!Array.isArray(docs)) docs = [];
  } catch(e) {
    docs = [];
  }

  const referer = item.json.allrisUrl || 'https://www.goslar.de/stadt/politik/allris/vo040_r.asp?SORT=2vofdat';

  const base = {
    vorgangKey:        item.json.vorgangKey,
    volfdnr:           item.json.volfdnr           || '',
    title:             item.json.title,
    vorgangsnummer:    item.json.vorgangsnummer,
    sourceUrl:         item.json.sourceUrl          || '',
    allrisUrl:         item.json.allrisUrl,
    documentCount:     item.json.documentCount,
    documentsJson:     item.json.documentsJson,
    vorfilterThemen:   item.json.vorfilterThemen    || [],
    vorfilterKeywords: item.json.vorfilterKeywords  || [],
    vorfilterScore:    item.json.vorfilterScore     || 0,
    isKnown:           item.json.isKnown            || false,
    needsRefresh:      item.json.needsRefresh       !== false,
    oldContentStage:   item.json.oldContentStage    || '',
    oldContentErrorReason: item.json.oldContentErrorReason || '',
    documentsChanged:  item.json.documentsChanged   === true,
    stammVorgangsnummer: item.json.stammVorgangsnummer || item.json.vorgangsnummer || '',
    folgeNummer:         item.json.folgeNummer        || '',
    istFolgevorgang:     item.json.istFolgevorgang    === true,
    _docLoopInit:      true,
    referer
  };

  if (docs.length === 0) {
    // Platzhalter-Item für Vorgänge ohne Dokumente
    const docRunKey = `${item.json.vorgangKey}::__none__`;
    out.push({ json: {
      ...base,
      url:       '',
      type:      'none',
      docKey:    '',
      label:     '',
      docRunKey
    }});
  } else {
    for (const doc of docs) {
      const docRunKey = `${item.json.vorgangKey}::${doc.docKey || doc.url}`;
      out.push({ json: {
        ...base,
        url:    doc.url,
        type:   doc.type,
        docKey: doc.docKey || '',
        label:  doc.label  || '',
        docRunKey
      }});
    }
  }
}
return out;

// Handle Extract – normalisiert genau ein Dokument-Ergebnis.
// Wird einmal pro Dokument im Dokument-Loop aufgerufen.
// Mögliche Eingangsquellen:
//   a) Markiere kein Dokument → type='none'
//   b) IF sendToTika? false-Zweig → sendToTika=false
//   c) Metadaten nach Tika → tikaText vorhanden

const item = {
  json: $json,
  binary: $binary
};

const base = {
  vorgangKey:        item.json.vorgangKey        || '',
  volfdnr:           item.json.volfdnr           || '',
  title:             item.json.title             || '',
  vorgangsnummer:    item.json.vorgangsnummer     || '',
  sourceUrl:         item.json.sourceUrl          || '',
  allrisUrl:         item.json.allrisUrl          || '',
  documentCount:     item.json.documentCount      || 0,
  documentsJson:     item.json.documentsJson      || '[]',
  vorfilterThemen:   item.json.vorfilterThemen    || [],
  vorfilterKeywords: item.json.vorfilterKeywords  || [],
  vorfilterScore:    item.json.vorfilterScore     || 0,
  isKnown:           item.json.isKnown            || false,
  needsRefresh:      item.json.needsRefresh       !== false,
  oldContentStage:   item.json.oldContentStage    || '',
  oldContentErrorReason: item.json.oldContentErrorReason || '',
  documentsChanged:  item.json.documentsChanged   === true,
  stammVorgangsnummer: item.json.stammVorgangsnummer || '',
  folgeNummer:         item.json.folgeNummer        || '',
  istFolgevorgang:     item.json.istFolgevorgang    === true,
  url:               item.json.url               || '',
  type:              item.json.type              || '',
  docKey:            item.json.docKey            || '',
  label:             item.json.label             || '',
  docRunKey:         item.json.docRunKey         || ''
};

// ── Fall a) Vorgang ohne Dokument ─────────────────────────────────────────
if (item.json.type === 'none' || item.json.textExtractionMethod === 'no_document') {
  return {
    json: {
      ...base,
      text:                   '',
      textExtractionSuccess:  false,
      textLength:             0,
      textExtractionMethod:   'no_document',
      textExtractionError:    ''
    }
  };
}

// ── Fall b) Binary-Fehler / ZIP (sendToTika === false) ────────────────────
if (item.json.sendToTika === false) {
  return {
    json: {
      ...base,
      text:                   '',
      textExtractionSuccess:  item.json.textExtractionSuccess || false,
      textLength:             item.json.textLength            || 0,
      textExtractionMethod:   item.json.textExtractionMethod  || 'download_failed',
      textExtractionError:    item.json.textExtractionError   || 'Download fehlgeschlagen'
    }
  };
}

// ── Fall c) Tika-Ergebnis ─────────────────────────────────────────────────
const tikaError = item.json.tikaError || item.json.error?.message || '';

let rawText =
  typeof item.json.tikaText  === 'string' ? item.json.tikaText  :
  typeof item.json.data      === 'string' ? item.json.data      :
  typeof item.json.body      === 'string' ? item.json.body      :
  null;

const text = typeof rawText === 'string' ? rawText.trim() : '';

let textExtractionSuccess, textExtractionMethod, textExtractionError;

if (text.length > 0) {
  textExtractionSuccess = true;
  textExtractionMethod  = 'tika';
  textExtractionError   = '';
} else if (tikaError) {
  textExtractionSuccess = false;
  textExtractionMethod  = 'tika_error';
  textExtractionError   = tikaError;
} else {
  textExtractionSuccess = false;
  textExtractionMethod  = 'tika_empty';
  textExtractionError   = 'Tika lieferte keinen Dokumenttext';
}

return {
  json: {
    ...base,
    text,
    textExtractionSuccess,
    textLength:  text.length,
    textExtractionMethod,
    textExtractionError
  }
};

// Vorgangs-Metadaten robust über "Expand Documents" holen (1:1 pro Vorgang).
// "Loop Dokumente" hat (alwaysOutputData) schon mehrfach einen Phantom-Aufruf
// ausgelöst, bei dem der runIndex nicht zu "Expand Documents" passt. Ein
// einzelner solcher Ausreißer darf NIE die gesamte Ausführung abbrechen –
// deshalb hier überspringen (kein Ergebnis) statt werfen; der Vorgang bleibt
// als needsRefresh stehen und wird beim nächsten geplanten Lauf erneut versucht.
let expandItems = [];
try {
  expandItems = $('Expand Documents').all(0, $runIndex);
} catch (e) {
  expandItems = [];
}

// Sicherer Platzhalter, falls dieser Vorgang übersprungen werden muss:
// vorgangKey bleibt leer, isKnown:true routet auf "Update bekannter Vorgang",
// dessen Filter (keyValue={{$json.vorgangKey}}) dann keine Zeile trifft –
// also ein No-Op-Update statt eines falschen Inserts. Wichtig ist nur, dass
// die Kette weiterläuft und "Loop Vorgangsseiten" wieder getriggert wird.
const skipResult = [{ json: { vorgangKey: '', isKnown: true, needsRefresh: false, _skippedPhantomAggregate: true } }];

if (!expandItems || expandItems.length === 0) {
  console.warn(
    `[Aggregate Texts] Keine Vorgangsdaten von "Expand Documents" bei runIndex=${$runIndex} ` +
    `(vermutlich Phantom-Aufruf von "Loop Dokumente") – Vorgang wird übersprungen.`
  );
  return skipResult;
}

const vorgangMeta = expandItems[0].json || {};
const currentVorgangKey = String(vorgangMeta.vorgangKey || '').trim();

if (!currentVorgangKey) {
  console.warn(
    `[Aggregate Texts] "Expand Documents"-Item besitzt keinen vorgangKey bei runIndex=${$runIndex} – Vorgang wird übersprungen.`
  );
  return skipResult;
}

// $input (der "done"-Ausgang von "Loop Dokumente") liefert die Loop-Ergebnisse
// nicht zuverlässig. Stattdessen alle bisher von "Handle Extract" produzierten
// Items holen (über die gesamte Ausführung hinweg) und auf den aktuellen
// vorgangKey filtern. Wurde "Handle Extract" in diesem Lauf noch gar nicht
// ausgeführt (z.B. weil kein Dokument verarbeitet wurde), gilt das als 0 Dokumente.
let handleExtractItems = [];
try {
  handleExtractItems = $('Handle Extract').all();
} catch (e) {
  handleExtractItems = [];
}

const filteredItems = handleExtractItems.filter(item =>
  String(item?.json?.vorgangKey || '').trim() === currentVorgangKey
);

// Innerhalb des Vorgangs Dokumente noch einmal absichern,
// damit ein Dokument nicht doppelt aggregiert wird.
const uniqueItemsMap = new Map();

for (const item of filteredItems) {
  const json = item.json || {};

  const uniqueKey =
    String(json.docRunKey || '').trim() ||
    String(json.docKey || '').trim() ||
    String(json.url || '').trim() ||
    `${currentVorgangKey}::__none__`;

  if (!uniqueItemsMap.has(uniqueKey)) {
    uniqueItemsMap.set(uniqueKey, item);
  }
}

const allItems = [...uniqueItemsMap.values()];

console.log(
  `[Aggregate Texts] aktuell=${currentVorgangKey}; ` +
  `HandleExtractGesamt=${handleExtractItems.length}; ` +
  `gefiltert=${filteredItems.length}; ` +
  `eindeutig=${allItems.length}; ` +
  `runIndex=${$runIndex}`
);

const group = {
  vorgangKey: currentVorgangKey,
  volfdnr: vorgangMeta.volfdnr || '',
  title: vorgangMeta.title || '',
  vorgangsnummer: vorgangMeta.vorgangsnummer || '',
  sourceUrl: vorgangMeta.sourceUrl || '',
  allrisUrl: vorgangMeta.allrisUrl || '',
  documentCount: Number(vorgangMeta.documentCount || 0),
  documentsJson: vorgangMeta.documentsJson || '[]',
  vorfilterThemen: vorgangMeta.vorfilterThemen || [],
  vorfilterKeywords: vorgangMeta.vorfilterKeywords || [],
  vorfilterScore: vorgangMeta.vorfilterScore || 0,
  isKnown: vorgangMeta.isKnown === true,
  needsRefresh: vorgangMeta.needsRefresh !== false,
  oldContentStage: vorgangMeta.oldContentStage || '',
  oldContentErrorReason: vorgangMeta.oldContentErrorReason || '',
  documentsChanged: vorgangMeta.documentsChanged === true,
  stammVorgangsnummer: vorgangMeta.stammVorgangsnummer || vorgangMeta.vorgangsnummer || '',
  folgeNummer: String(vorgangMeta.folgeNummer || ''),
  istFolgevorgang: vorgangMeta.istFolgevorgang === true,
  texts: [],
  extractedCount: 0,
  failedCount: 0
};

for (const item of allItems) {
  const json = item.json || {};

  const text = String(json.text || '').trim();
  const method = String(json.textExtractionMethod || '');
  const success = json.textExtractionSuccess === true;
  const isPlaceholder =
    method === 'no_document' ||
    json.type === 'none' ||
    !json.url;

  if (isPlaceholder) {
    continue;
  }

  if (success && text) {
    group.extractedCount++;

    const docLabel = json.label || json.docKey || `Dokument ${group.extractedCount}`;

    group.texts.push(
      `--- Dokument ${group.extractedCount}: ${docLabel} ---\n${text}`
    );
  } else {
    group.failedCount++;

    const docLabel = json.label || json.docKey || 'Dokument';

    console.warn(
      `[Aggregate Texts] Extraktion fehlgeschlagen: ${currentVorgangKey}/${docLabel}; ` +
      `method=${method}; error="${json.textExtractionError || ''}"`
    );
  }
}

const combinedText =
  group.texts.length > 0
    ? group.texts.join('\n\n')
    : Number(group.documentCount || 0) > 0
      ? '(Dokumentlinks gefunden, aber kein Dokumenttext extrahierbar)'
      : '(Keine Dokumentlinks gefunden)';

return [{
  json: {
    vorgangKey: group.vorgangKey,
    volfdnr: group.volfdnr,
    title: group.title,
    vorgangsnummer: group.vorgangsnummer,
    stammVorgangsnummer: group.stammVorgangsnummer || group.vorgangsnummer || '',
    folgeNummer: String(group.folgeNummer || ''),
    istFolgevorgang: group.istFolgevorgang === true,
    sourceUrl: group.sourceUrl,
    allrisUrl: group.allrisUrl,
    documentCount: group.documentCount,
    documentsJson: group.documentsJson,
    vorfilterThemen: group.vorfilterThemen,
    vorfilterKeywords: group.vorfilterKeywords,
    vorfilterScore: group.vorfilterScore,
    isKnown: group.isKnown,
    needsRefresh: group.needsRefresh,
    oldContentStage: group.oldContentStage || '',
    oldContentErrorReason: group.oldContentErrorReason || '',
    documentsChanged: group.documentsChanged === true,
    extractedDocumentCount: group.extractedCount,
    failedDocumentCount: group.failedCount,
    combinedTextLength: combinedText.length,
    combinedText
  }
}];

const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // HTTP ALLRIS Übersicht läuft mit neverError: true – Fehlerstatus muss hier
  // explizit geprüft werden, sonst würde eine Fehlerseite (5xx/4xx) stillschweigend
  // als HTML verarbeitet und ergäbe 0 Vorgangslinks statt eines sichtbaren Fehlers.
  const statusCode = Number(item.json.statusCode ?? item.json.response?.statusCode ?? 0);
  if (statusCode >= 400) {
    throw new Error(`[codepage] HTTP ALLRIS Übersicht fehlgeschlagen: Status ${statusCode}`);
  }

  // Binary lesen und latin1 dekodieren
  let html = '';
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    html = buffer.toString('latin1')
      .replace(/&amp;/g, '&')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&uuml;/g, 'ü')
      .replace(/&Uuml;/g, 'Ü')
      .replace(/&ouml;/g, 'ö')
      .replace(/&Ouml;/g, 'Ö')
      .replace(/&auml;/g, 'ä')
      .replace(/&Auml;/g, 'Ä')
      .replace(/&szlig;/g, 'ß');
  } catch(e) {
    console.warn(`[codepage] Item ${i}: Fehler beim Lesen des Binary: ${e.message}`);
    html = '';
  }

  out.push({
    json: {
      ...item.json,
      data: html,
      html
    }
  });
}

return out;

// Lädt zusätzliche ALLRIS-Übersichtsseiten über die Session-Cookie-basierte
// shownext-Paginierung (vo040_r.asp?shownext=true). Extrahiert pro Seite
// sofort nur die VOLFDNR-Link-Fragmente und verwirft den Rest der Seite
// (Menüs, CSS/JS, Footer) - eine komplette Übersichtsseite ist mehrere
// hundert KB groß, obwohl nur wenige KB an Links tatsächlich gebraucht
// werden. Wichtig auf einer knapp bemessenen VM (siehe RAM-Vorfall 2026-07-02).
//
// Getestet: shownext=true liefert bei gleicher ASP-Session jedes Mal eine
// neue, ältere Seite mit ca. 49-50 bisher nicht enthaltenen VOLFDNR-Links.
// Ohne gültigen Session-Cookie liefert shownext=true wieder Seite 1.
//
// Anzahl zusätzlicher Seiten hier einstellen:
//   0 = nur Seite 1 (bisheriges Verhalten)
//   1 = Seite 1 + 1 weitere Seite, deckt die letzten ca. 95-100 Vorgänge ab
const ZUSAETZLICHE_SEITEN = 1;

const item = items[0] || { json: {} };
const j = item.json || {};

let html = String(j.data || j.html || '');

if (ZUSAETZLICHE_SEITEN <= 0) {
  return [{ json: { ...j, data: html, html, _uebersichtSeitenGeladen: 1 } }];
}

function extractCookieHeader(headers) {
  const raw = (headers && (headers['set-cookie'] || headers['Set-Cookie'])) || [];
  const list = Array.isArray(raw) ? raw : [raw];
  return list.map(c => String(c || '').split(';')[0]).filter(Boolean).join('; ');
}

let firstPageJson = {};
try {
  firstPageJson = $('HTTP ALLRIS Übersicht').first().json || {};
} catch (e) {
  console.warn('[WeitereSeiten] Konnte HTTP ALLRIS Übersicht nicht referenzieren.');
}

const cookieHeader = extractCookieHeader(firstPageJson.headers);
if (!cookieHeader) {
  console.warn('[WeitereSeiten] Kein Session-Cookie aus Seite 1 gefunden – weitere Seiten liefern evtl. Seite 1 erneut.');
}

let geladeneSeiten = 1;

for (let i = 0; i < ZUSAETZLICHE_SEITEN; i++) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.goslar.de/stadt/politik/allris/vo040_r.asp?shownext=true',
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/124 Safari/537.36',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'de-DE,de;q=0.9,en;q=0.8',
        'Referer': 'https://www.goslar.de/stadt/politik/allris/vo040_r.asp',
        ...(cookieHeader ? { Cookie: cookieHeader } : {})
      },
      proxy: 'http://172.16.1.5:3128',
      returnFullResponse: true,
      encoding: 'arraybuffer',
      timeout: 30000
    });

    // response.body kann je nach n8n-Version ein echter Buffer, ein
    // serialisiertes Buffer-Objekt ({type:'Buffer',data:[...]}) oder ein
    // bereits dekodierter String sein. Unbekannte Objektformen NICHT per
    // String(...) in Text verwandeln - das ergibt sonst "[object Object]"
    // und verunreinigt die gesammelten Vorgangslinks mit Datenmüll.
    let pageHtml = '';
    if (Buffer.isBuffer(response.body)) {
      pageHtml = response.body.toString('latin1');
    } else if (response.body && typeof response.body === 'object' && response.body.type === 'Buffer' && Array.isArray(response.body.data)) {
      pageHtml = Buffer.from(response.body.data).toString('latin1');
    } else if (typeof response.body === 'string') {
      pageHtml = response.body;
    } else {
      console.warn(`[WeitereSeiten] Seite ${i + 2}: unerwarteter body-Typ (${typeof response.body}), Inhalt wird verworfen statt angehängt.`);
    }

    pageHtml = pageHtml
      .replace(/&amp;/g, '&')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/&uuml;/g, 'ü')
      .replace(/&Uuml;/g, 'Ü')
      .replace(/&ouml;/g, 'ö')
      .replace(/&Ouml;/g, 'Ö')
      .replace(/&auml;/g, 'ä')
      .replace(/&Auml;/g, 'Ä')
      .replace(/&szlig;/g, 'ß');

    // Nur die relevanten <a href=...VOLFDNR=...>-Fragmente behalten statt der
    // kompletten Seite - reduziert den Speicherbedarf pro Seite von mehreren
    // hundert KB auf wenige KB. "Extrahiere Vorgangslinks" findet dieselben
    // Treffer in diesem kleinen Ausschnitt genauso, da es denselben Regex nutzt.
    const linkFragmente = pageHtml.match(/<a[^>]+href=["'][^"']*vo020_r\.asp\?VOLFDNR=\d+[^"']*["'][^>]*>/gi) || [];

    if (linkFragmente.length === 0) {
      console.warn(`[WeitereSeiten] Seite ${i + 2}: keine VOLFDNR-Links gefunden (${pageHtml.length} Zeichen Rohseite), wird nicht angehängt.`);
    } else {
      html = html + ' ' + linkFragmente.join(' ');
      geladeneSeiten++;
      console.log(`[WeitereSeiten] Seite ${i + 2} geladen (${linkFragmente.length} Links, ${pageHtml.length} Zeichen Rohseite verworfen).`);
    }
  } catch (e) {
    console.warn(`[WeitereSeiten] Seite ${i + 2} fehlgeschlagen: ${e.message}. Bisherige Seiten bleiben erhalten.`);
    break;
  }

  await new Promise(resolve => setTimeout(resolve, 1500));
}

return [{
  json: {
    ...j,
    data: html,
    html,
    _uebersichtSeitenGeladen: geladeneSeiten
  }
}];

// Cookie Refresh: dekodiert HTML-Body und rettet Originalfelder aus dem Loop-Item.
// Verwendet $runIndex-sichere Zugriffe statt .all() ohne runIndex.

const out = [];

// Aktuellen Lauf: HTTP-Antworten und Normalisierte URLs mit $runIndex absichern
const responseItems    = $input.all(0, $runIndex);
const normalizedItems  = $('Normalisiere Vorgangsseiten URL').all(0, $runIndex);

if (responseItems.length !== normalizedItems.length) {
  console.warn(
    `[Cookie Refresh] Anzahl HTTP-Antworten (${responseItems.length}) ` +
    `stimmt nicht mit Normalisierungs-Items (${normalizedItems.length}) überein ` +
    `– runIndex=${$runIndex}`
  );
}

for (let i = 0; i < responseItems.length; i++) {
  const item     = responseItems[i];
  const original = normalizedItems[i]?.json || {};

  // VOLFDNR-Konsistenzprüfung
  if (
    original.volfdnr &&
    item.json.volfdnr &&
    String(original.volfdnr) !== String(item.json.volfdnr)
  ) {
    throw new Error(
      `[Cookie Refresh] VOLFDNR-Zuordnung widersprüchlich: ` +
      `${original.volfdnr} != ${item.json.volfdnr} runIndex=${$runIndex} i=${i}`
    );
  }

  // HTML robust ermitteln
  let html = item.json.html || item.json.data || item.json.body || '';

  let binaryKeys = [];
  if (!html) {
    try {
      binaryKeys = Object.keys(item.binary || {});
    } catch(e) { binaryKeys = []; }

    const binaryKey = binaryKeys.includes('data') ? 'data' : (binaryKeys[0] || null);

    if (binaryKey) {
      try {
        const buffer = await this.helpers.getBinaryDataBuffer(i, binaryKey);
        html = buffer.toString('latin1');
        console.log(`[Cookie Refresh] Item ${i}: Binary gelesen via key="${binaryKey}", Länge=${html.length}`);
      } catch(e) {
        console.warn(`[Cookie Refresh] Item ${i}: Binary-Lesefehler (key=${binaryKey}): ${e.message}`);
        html = '';
      }
    } else {
      console.warn(`[Cookie Refresh] Item ${i}: Kein Binary vorhanden. statusCode=${item.json.statusCode || '?'}`);
    }
  }

  // HTML-Entities ersetzen
  html = String(html || '')
    .replace(/&amp;/g, '&').replace(/&quot;/g, '"').replace(/&#39;/g, "'")
    .replace(/&uuml;/g, 'ü').replace(/&Uuml;/g, 'Ü')
    .replace(/&ouml;/g, 'ö').replace(/&Ouml;/g, 'Ö')
    .replace(/&auml;/g, 'ä').replace(/&Auml;/g, 'Ä')
    .replace(/&szlig;/g, 'ß');

  // Originalfelder sichern
  const rawSourceUrl =
    original.sourceUrl  || original.url ||
    item.json.sourceUrl || item.json.url || '';

  const volfdnr =
    original.volfdnr    || original.docId    ||
    item.json.volfdnr   || item.json.docId   ||
    rawSourceUrl.match(/VOLFDNR=(\d+)/i)?.[1] ||
    '';

  const canonicalUrl = volfdnr
    ? `https://www.goslar.de/stadt/politik/allris/vo020_r.asp?VOLFDNR=${volfdnr}`
    : rawSourceUrl;

  const debug_statusCode = item.json.statusCode ||
    item.json.response?.statusCode || '';
  const debug_hasError   = !!(item.json.error);

  out.push({
    json: {
      url:           canonicalUrl,
      requestUrl:    canonicalUrl,
      sourceUrl:     canonicalUrl,
      allrisUrl:     canonicalUrl,
      volfdnr,
      docId:         volfdnr,
      source:        original.source || 'ALLRIS Goslar',
      type:          original.type   || 'vorgang',
      ...item.json,
      url:           canonicalUrl,
      requestUrl:    canonicalUrl,
      sourceUrl:     canonicalUrl,
      allrisUrl:     canonicalUrl,
      volfdnr,
      docId:         volfdnr,
      data:          html,
      html,
      error:         item.json.error || undefined,
      debug_currentVolfdnr:  volfdnr,
      debug_sourceUrlPresent: canonicalUrl.length > 0,
      debug_allrisUrlPresent: canonicalUrl.length > 0,
      debug_binaryKeys:       binaryKeys,
      debug_htmlLength:       html.length,
      debug_statusCode,
      debug_hasError,
      debug_runIndex: $runIndex
    }
  });
}

return out;

function extractVorgangsnummer(text) {
  if (!text) return '';
  const m = String(text).match(/\b(\d{4})\s*\/\s*(\d+)(?:-(\d+))?\b/);
  if (!m) return '';
  return m[1] + '/' + m[2] + (m[3] ? '-' + m[3] : '');
}

const HTTP_ERROR_TITLE_RE = /^\s*(?:400[\s:-]+bad\s+request|401[\s:-]+unauthorized|403[\s:-]+forbidden|404[\s:-]+not\s+found|408[\s:-]+request\s+time[- ]?out|429[\s:-]+too\s+many\s+requests|500[\s:-]+internal\s+server\s+error|501[\s:-]+not\s+implemented|502[\s:-]+bad\s+gateway|503[\s:-]+service\s+unavailable|504[\s:-]+gateway\s*time[- ]?out)\s*$/i;

const TECH_ERROR_PHRASE_RE = /gateway\s*time[- ]?out|bad\s+gateway|service\s+unavailable|internal\s+server\s+error|request\s+time[- ]?out|upstream\s+timed\s+out|proxy\s+error|temporarily\s+unavailable|too\s+many\s+requests|serverfehler|nginx\s+error|cloudflare\s+error/i;

function isTechnicalTitle(value) {
  const text = String(value || '').trim();
  return HTTP_ERROR_TITLE_RE.test(text) || TECH_ERROR_PHRASE_RE.test(text);
}

function containsTechnicalErrorPhrase(value) {
  return TECH_ERROR_PHRASE_RE.test(String(value || ''));
}

function isValidVorgangsnummer(v) {
  return /^\d{4}\/\d+(?:-\d+)?$/.test(String(v || '').trim());
}

// Vorgangsseite Fallback – V29.1 präzise Fehlererkennung
const MIN_HTML_LENGTH = 500;
const out = [];

for (const item of items) {
  const rawHtml = item.json.html || item.json.data || '';
  const title   = rawHtml.match(/<title>(.*?)<\/title>/is)?.[1]?.trim() || '';
  const isError = !!(item.json.error) || item.json.debug_hasError === true;

  const volfdnr =
    item.json.volfdnr || item.json.docId ||
    (item.json.sourceUrl || '').match(/VOLFDNR=(\d+)/i)?.[1] || '';

  const canonicalUrl = volfdnr
    ? `https://www.goslar.de/stadt/politik/allris/vo020_r.asp?VOLFDNR=${volfdnr}`
    : (item.json.allrisUrl || item.json.sourceUrl || item.json.url || '');

  const statusCode = Number(
    item.json.statusCode ??
    item.json.response?.statusCode ??
    item.json.debug_statusCode ??
    item.json.error?.statusCode ??
    0
  );

  const debugBase = {
    debug_htmlLength:     rawHtml.length,
    debug_statusCode:     statusCode || item.json.debug_statusCode || '',
    debug_hasError:       isError,
    debug_requestUrl:     item.json.requestUrl || item.json.url || canonicalUrl,
    debug_currentVolfdnr: volfdnr
  };

  // ── Drei getrennte Fehlerbedingungen ──────────────────────────────────────
  const httpError  = isError || (Number.isFinite(statusCode) && statusCode >= 400);
  const htmlTooShort = rawHtml.length < MIN_HTML_LENGTH;
  const techTitle  = isTechnicalTitle(title);
  const techBody   = !techTitle && containsTechnicalErrorPhrase(rawHtml.slice(0, 5000));
  const emptyTitle = !title;

  const vorgangsnummer =
    extractVorgangsnummer(item.json.vorgangsnummer || '') ||
    extractVorgangsnummer(title) ||
    extractVorgangsnummer(rawHtml);
  const missingVorgangsnummer = !vorgangsnummer;

  let pageErrorReason = '';
  if (httpError) {
    pageErrorReason = (Number.isFinite(statusCode) && statusCode >= 400)
      ? `http_${statusCode}` : 'http_error';
  } else if (htmlTooShort) {
    pageErrorReason = 'html_too_short';
  } else if (techTitle) {
    pageErrorReason = 'technical_error_title';
  } else if (techBody) {
    pageErrorReason = 'technical_error_body';
  } else if (emptyTitle) {
    pageErrorReason = 'empty_title';
  } else if (missingVorgangsnummer) {
    pageErrorReason = 'missing_vorgangsnummer';
  }

  const isFailed = !!(pageErrorReason);

  if (!isFailed) {
    out.push({ json: {
      ...item.json,
      sourceUrl:          canonicalUrl,
      allrisUrl:          canonicalUrl,
      volfdnr,
      title,
      vorgangsnummer,
      detailStatus:       'ok',
      debug_detailStatus: 'ok',
      ...debugBase
    }});
  } else {
    console.warn(`[Vorgangsseite Fallback] detail_failed: volfdnr=${volfdnr} reason=${pageErrorReason} status=${statusCode} htmlLen=${rawHtml.length} title="${title}"`);
    out.push({ json: {
      source:             'ALLRIS Goslar',
      sourceUrl:          canonicalUrl,
      allrisUrl:          canonicalUrl,
      volfdnr,
      vorgangKey:         volfdnr ? `vol_${volfdnr}` : `url_${encodeURIComponent(canonicalUrl).slice(0,40)}`,
      title:              '',
      vorgangsnummer:     '',
      html:               '',
      detailStatus:       'detail_failed',
      debug_detailStatus: 'detail_failed',
      technicalPageDetected: true,
      detectedStatusCode:  statusCode,
      pageErrorReason,
      length:             0,
      combinedText:       '(Vorgangsseite konnte nicht geladen werden)',
      ...debugBase
    }});
  }
}

return out;

// Vorgangsseite konnte nicht geladen werden. Platzhalter-Item erstellen.
return items.map(item => {
  const volfdnr   = item.json.volfdnr || item.json.docId || '';
  const sourceUrl = item.json.sourceUrl || item.json.url || '';
  const allrisUrl = item.json.allrisUrl ||
    (volfdnr
      ? `https://www.goslar.de/stadt/politik/allris/vo020_r.asp?VOLFDNR=${volfdnr}`
      : sourceUrl);
  const vorgangKey = volfdnr
    ? `vol_${volfdnr}`
    : `url_${encodeURIComponent(sourceUrl).slice(0, 40)}`;

  console.log(`[Insert fehlgeschlagener Vorgang] vorgangKey=${vorgangKey} volfdnr=${volfdnr}`);

  return {
    json: {
      vorgangKey,
      volfdnr,
      title:             '(Vorgangsseite nicht geladen)',
      vorgangsnummer:    '',
      sourceUrl,
      allrisUrl,
      firstseen:         new Date().toISOString(),
      lastseen:          new Date().toISOString(),
      vorfilterThemen:   [],
      vorfilterKeywords: [],
      vorfilterScore:    0,
      documentsJson:     '[]',
      documentCount:     0,
      combinedText:      '(Vorgangsseite konnte nicht geladen werden)',
      isKnown:           false,
      needsRefresh:      false,
      debug_loopPhase:   'insert_fehlgeschlagen'
    }
  };
});

// Check Detail Known – $runIndex-sicher
// Prüft ob der aktuell fehlgeschlagene Vorgang bereits in der DataTable existiert.
// Get Vorgaenge Detail Failed liefert nur Treffer für den aktuellen vorgangKey.

const failedItems = $('Insert fehlgeschlagener Vorgang').all(0, $runIndex);

if (!failedItems || failedItems.length !== 1) {
  throw new Error(
    `[Check Detail Known] Erwartet 1 fehlgeschlagenen Vorgang, ` +
    `erhalten: ${failedItems?.length ?? 0}, runIndex=${$runIndex}`
  );
}

const failed = failedItems[0].json || {};

// DataTable-Einträge für diesen vorgangKey (gefiltert durch Get Vorgaenge Detail Failed)
const rows = $input.all(0, $runIndex)
  .map(item => item.json || {})
  .filter(row => !!row.vorgangKey);

const matchingRows = rows.filter(
  row => String(row.vorgangKey || '').trim() === String(failed.vorgangKey || '').trim()
);

if (matchingRows.length > 1) {
  console.warn(
    `[Check Detail Known] Bereits vorhandene Duplikate: ` +
    `key=${failed.vorgangKey}, count=${matchingRows.length}, runIndex=${$runIndex}`
  );
}

const old = matchingRows[0];

console.log(
  `[Check Detail Known] vorgangKey=${failed.vorgangKey} ` +
  `alreadyInTable=${!!old} oldContentStage=${old?.contentStage || ''} runIndex=${$runIndex}`
);

return [{
  json: {
    ...failed,
    alreadyInTable:  !!old,
    oldContentStage: String(old?.contentStage || '').trim(),
    oldContentErrorReason: String(old?.contentErrorReason || '').trim(),
    oldCombinedText: old?.combinedText  || '',
    debug_loopPhase: 'check_detail_known',
    debug_runIndex:  $runIndex
  }
}];

// Stellt sicher, dass HTTP Vorgangsseiten immer eine absolute URL bekommt.
// Baut außerdem kanonische sourceUrl/allrisUrl aus volfdnr.

return items.map(item => {
  const raw =
    item.json.url        ||
    item.json.allrisUrl  ||
    item.json.sourceUrl  ||
    '';

  let requestUrl = raw;
  try {
    requestUrl = raw.startsWith('http')
      ? raw
      : new URL(raw, 'https://www.goslar.de/stadt/politik/allris/vo040_r.asp').href;
  } catch(e) {
    requestUrl = raw;
  }

  const volfdnr =
    item.json.volfdnr  ||
    item.json.docId    ||
    requestUrl.match(/VOLFDNR=(\d+)/i)?.[1] ||
    '';

  const canonicalUrl = volfdnr
    ? `https://www.goslar.de/stadt/politik/allris/vo020_r.asp?VOLFDNR=${volfdnr}`
    : requestUrl;

  return {
    json: {
      ...item.json,
      url:        canonicalUrl,
      requestUrl: canonicalUrl,
      sourceUrl:  canonicalUrl,
      allrisUrl:  canonicalUrl,
      volfdnr,
      docId:      volfdnr,
      debug_requestUrl:  canonicalUrl,
      debug_loopPhase:   'detail_url_normalized',
      debug_currentVolfdnr: volfdnr
    }
  };
});

// TESTFILTER – nur eine einzelne ALLRIS-Vorlage verarbeiten
// Zum Deaktivieren: TEST_MODE = false setzen

const TEST_MODE = false;

// TEMPORAER 2026-07-18: Begrenzt auf die ersten N Vorgaenge nach dem DB-Wipe,
// um den End-to-End-Test des neuen Agenten-Cutovers ueberschaubar zu halten.
// Auf 0 setzen (oder Zeile entfernen) um die Begrenzung wieder abzuschalten.
const TEST_LIMIT_COUNT = 10;

// Hier deine VOLFDNR eintragen
// Beispiel aus deinem Screenshot: vo020_r.asp?VOLFDNR=10723
const TEST_VOLFDNR = '10719';

if (!TEST_MODE) {
  if (TEST_LIMIT_COUNT > 0 && items.length > TEST_LIMIT_COUNT) {
    // Bereits bekannte Vorgaenge (per volfdnr) rausfiltern, BEVOR auf TEST_LIMIT_COUNT
    // geschnitten wird - sonst besteht die Auswahl bei einem erneuten Lauf oft nur aus
    // laengst bekannten Vorgaengen (kein neuer Insert, nur lastseen-Update) statt echter
    // neuer Testdaten. So verhaelt sich TEST_LIMIT_COUNT wie eine echte 'naechste N unbekannte
    // Vorgaenge'-Pagination ueber mehrere Laeufe hinweg.
    let knownVolfdnr = new Set();
    try {
      knownVolfdnr = new Set(
        $('Hole bekannte Volfdnr').all()
          .map(i => String((i.json && i.json.volfdnr) || '').trim())
          .filter(Boolean)
      );
    } catch (e) {
      console.warn(`[Testfilter] Konnte bekannte Volfdnr nicht laden, ueberspringe Known-Filter: ${e.message}`);
    }
    const unknownItems = items.filter(item => !knownVolfdnr.has(String(item.json.volfdnr || '').trim()));
    const limited = unknownItems.slice(0, TEST_LIMIT_COUNT);
    console.log(`[Testfilter] TEST_LIMIT_COUNT aktiv: ${items.length} gefunden, ${unknownItems.length} noch unbekannt, ${limited.length} werden verarbeitet.`);
    return limited;
  }
  return items;
}

const filtered = items.filter(item => {
  const volfdnr =
    String(item.json.volfdnr || '') ||
    String(item.json.docId || '') ||
    String(item.json.sourceUrl || '').match(/VOLFDNR=(\d+)/i)?.[1] ||
    String(item.json.allrisUrl || '').match(/VOLFDNR=(\d+)/i)?.[1] ||
    '';

  return volfdnr === TEST_VOLFDNR;
});

if (filtered.length === 0) {
  throw new Error(`[Testfilter] Keine Vorlage mit VOLFDNR=${TEST_VOLFDNR} gefunden.`);
}

console.log(`[Testfilter] TEST_MODE aktiv: ${filtered.length} Vorgang mit VOLFDNR=${TEST_VOLFDNR} wird verarbeitet.`);

return filtered.map(item => ({
  json: {
    ...item.json,
    _testMode: true,
    _testOnlyVolfdnr: TEST_VOLFDNR
  }
}));

// Prüft das heruntergeladene Binary auf Gültigkeit.
// Setzt sendToTika: true/false für die nachfolgende IF-Node.
// Hat nur einen Ausgang – die Verzweigung erfolgt durch eine separate IF-Node.

const item = items[0];

async function checkItem(item, index) {
  const binData  = item.binary?.data;
  const mimeType = (binData?.mimeType || '').toLowerCase();
  const docUrl   = (item.json.url || '').toLowerCase();

  // ── 1. Binary-Feld vorhanden? ─────────────────────────────────────────────
  if (!binData) {
    return {
      ...item.json,
      sendToTika:            false,
      textExtractionSuccess: false,
      textLength:            0,
      textExtractionMethod:  'download_failed',
      textExtractionError:   'Kein Binary-Feld im HTTP-Response vorhanden'
    };
  }

  // ── 2. Buffer lesen (robust, kein Verlass auf fileSize-String) ────────────
  let buffer;
  try {
    buffer = await this.helpers.getBinaryDataBuffer(index, 'data');
  } catch(e) {
    return {
      ...item.json,
      sendToTika:            false,
      textExtractionSuccess: false,
      textLength:            0,
      textExtractionMethod:  'download_failed',
      textExtractionError:   `Binary-Buffer nicht lesbar: ${e.message}`
    };
  }

  if (!buffer || buffer.length === 0) {
    return {
      ...item.json,
      sendToTika:            false,
      textExtractionSuccess: false,
      textLength:            0,
      textExtractionMethod:  'download_failed',
      textExtractionError:   'Heruntergeladene Datei ist leer (0 Byte)'
    };
  }

  // ── 3. ZIP erkennen: Magic-Bytes PK (0x50 0x4B), MIME-Type, Endung ────────
  const isPkZip = buffer[0] === 0x50 && buffer[1] === 0x4B;
  const isZipMime = mimeType.includes('application/zip') || mimeType.includes('application/x-zip');
  const isZipExt  = docUrl.endsWith('.zip');

  if (isPkZip || isZipMime || isZipExt) {
    console.warn(`[Prüfe Binary] ZIP erkannt. docRunKey=${item.json.docRunKey} mimeType=${mimeType}`);
    return {
      ...item.json,
      sendToTika:            false,
      textExtractionSuccess: false,
      textLength:            0,
      textExtractionMethod:  'zip_skipped',
      textExtractionError:   `ZIP-Datei wird nicht als Dokumenttext verarbeitet (mimeType=${mimeType})`
    };
  }

  // ── 4. HTML-Fehlerseite erkennen – anhand Dateiinhalt, nicht nur MIME ─────
  // Prüfe die ersten 512 Byte als ASCII/Latin1
  const head = buffer.slice(0, 512).toString('latin1').trimStart().toLowerCase();
  const isHtml = head.startsWith('<!doctype html') ||
                 head.startsWith('<html')           ||
                 head.startsWith('<head')           ||
                 head.startsWith('<body')           ||
                 // gelegentlich BOM vorangestellt
                 head.replace(/^\ufeff/, '').startsWith('<!doctype');

  if (isHtml) {
    console.warn(`[Prüfe Binary] HTML-Inhalt erkannt statt Dokument. docRunKey=${item.json.docRunKey} mimeType=${mimeType}`);
    return {
      ...item.json,
      sendToTika:            false,
      textExtractionSuccess: false,
      textLength:            0,
      textExtractionMethod:  'download_failed',
      textExtractionError:   `HTML-Fehlerseite empfangen statt Dokument (mimeType=${mimeType})`
    };
  }

  // ── 5. Binary ist gültig ──────────────────────────────────────────────────
  console.log(`[Prüfe Binary] OK. docRunKey=${item.json.docRunKey} size=${buffer.length} mimeType=${mimeType}`);
  return {
    ...item.json,
    sendToTika: true
  };
}

const results = [];
for (let i = 0; i < items.length; i++) {
  try {
    const result = await checkItem.call(this, items[i], i);
    results.push({ json: result, binary: items[i].binary });
  } catch(e) {
    console.error(`[Prüfe Binary] Unerwarteter Fehler bei Item ${i}: ${e.message}`);
    results.push({ json: {
      ...items[i].json,
      sendToTika:            false,
      textExtractionSuccess: false,
      textLength:            0,
      textExtractionMethod:  'download_failed',
      textExtractionError:   `Unerwarteter Fehler: ${e.message}`
    }, binary: items[i].binary });
  }
}
return results;

// Metadaten nach Tika – Modus: Run Once for Each Item
// Stellt Vorgangs- und Dokumentmetadaten nach dem Tika-HTTP-Aufruf wieder her.
// Das aktuelle Item ist die Tika-HTTP-Antwort.
// Die ursprünglichen Metadaten kommen aus dem verknüpften Eingangsitem
// des True-Zweigs der IF-Node "IF sendToTika?".

// Metadaten aus dem verknüpften Item vor Tika holen (item-linking)
const meta = $('IF sendToTika?').item.json;

// Tika-Text: responseFormat=text legt den Text in json.data oder json.body ab.
// tikaText ist gesetzt wenn die HTTP-Node "Put Output in Field" verwendet.
const tikaText =
  typeof $json.tikaText === 'string' ? $json.tikaText :
  typeof $json.data     === 'string' ? $json.data     :
  typeof $json.body     === 'string' ? $json.body     :
  '';

// Tika-Fehler
const tikaError =
  $json.error?.message ||
  $json.message        ||
  '';

return {
  json: {
    vorgangKey:        meta.vorgangKey        || '',
    volfdnr:           meta.volfdnr           || '',
    title:             meta.title             || '',
    vorgangsnummer:    meta.vorgangsnummer     || '',
    sourceUrl:         meta.sourceUrl          || '',
    allrisUrl:         meta.allrisUrl          || '',
    documentCount:     meta.documentCount      || 0,
    documentsJson:     meta.documentsJson      || '[]',
    vorfilterThemen:   meta.vorfilterThemen    || [],
    vorfilterKeywords: meta.vorfilterKeywords  || [],
    vorfilterScore:    meta.vorfilterScore     || 0,
    isKnown:           meta.isKnown            || false,
    needsRefresh:      meta.needsRefresh       !== false,
    url:               meta.url               || '',
    type:              meta.type              || '',
    docKey:            meta.docKey            || '',
    label:             meta.label             || '',
    docRunKey:         meta.docRunKey         || '',
    referer:           meta.referer           || '',
    stammVorgangsnummer: meta.stammVorgangsnummer || meta.vorgangsnummer || '',
    folgeNummer:         String(meta.folgeNummer || ''),
    istFolgevorgang:     meta.istFolgevorgang === true ||
                         String(meta.istFolgevorgang || '').trim().toLowerCase() === 'true',
    sendToTika:        true,
    tikaText,
    tikaError
  }
};
